#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main(void) {
    int pipefd[2];
    if (pipe(pipefd) == -1) { perror("pipe"); return 1; }

    printf("Step 1: Original process PID=%d\n", getpid());

    pid_t pid1 = fork();
    if (pid1 == -1) { perror("fork"); return 1; }
    if (pid1 > 0) {
        /* Premier parent quitte */
        close(pipefd[1]);
        /* Lire les messages du daemon */
        char buf[256];
        FILE *f = fdopen(pipefd[0], "r");
        while (fgets(buf, sizeof(buf), f))
            printf("%s", buf);
        fclose(f);
        waitpid(pid1, NULL, 0);
        return 0;
    }

    /* Premier enfant */
    close(pipefd[0]);
    FILE *out = fdopen(pipefd[1], "w");

    pid_t sid = setsid();
    fprintf(out, "Step 2: setsid() new session SID=%d\n", sid);

    pid_t pid2 = fork();
    if (pid2 > 0) {
        /* Second parent quitte */
        fclose(out);
        _exit(0);
    }

    /* Processus daemon final */
    fprintf(out, "Step 3: Daemon PID=%d, SID=%d\n", getpid(), getsid(0));
    fprintf(out, "Step 4: Daemon detached from terminal\n");
    fclose(out);
    _exit(0);
}

